const body = $('Webhook').first().json.body;
const agents = body.eligible_agents || [];
const emails = agents.map(a => a.email).filter(Boolean);
return [{ json: { emails: emails.join(', '), agentCount: agents.length, slots: body.slots_summary || [], weekRange: body.week_range || '' } }];

